module multi_pipe_8bit #(
    parameter size = 8
) (
    input clk,
    input rst_n,
    input [size-1:0] mul_a,
    input [size-1:0] mul_b,
    input mul_en_in,
    output reg mul_en_out,
    output reg [size*2-1:0] mul_out
);

    reg [size-1:0] mul_a_reg, mul_b_reg;
    reg mul_en_out_reg;
    reg [size-1:0] partial_products [size-1:0];
    reg [size:0] sum [size:0];
    reg [size*2-1:0] final_product;
    integer i;

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            mul_a_reg <= 0;
            mul_b_reg <= 0;
            mul_en_out_reg <= 0;
            for (i = 0; i < size; i = i + 1) begin
                partial_products[i] <= 0;
            end
            for (i = 0; i <= size; i = i + 1) begin
                sum[i] <= 0;
            end
            final_product <= 0;
            mul_en_out <= 0;
        end else begin
            mul_a_reg <= mul_a;
            mul_b_reg <= mul_b;
            mul_en_out_reg <= mul_en_in;

            for (i = 0; i < size; i = i + 1) begin
                partial_products[i] <= mul_b_reg[i] ? mul_a_reg << i : 0;
            end

            sum[0] <= partial_products[0];
            for (i = 1; i < size; i = i + 1) begin
                sum[i] <= sum[i-1] + partial_products[i];
            end

            final_product <= sum[size];

            mul_en_out <= mul_en_out_reg;
            mul_out <= final_product;
        end
    end

endmodule
